export default function AdminLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const router = useRouter();
  const pathname = usePathname();
  const queryClient = useQueryClient();
  const [isLoading, setIsLoading] = useState(true);

  const { data: authData, isError } = useQuery<AuthResponse>({
    queryKey: ["admin-auth"],
    queryFn: async () => {
      const response = await fetch("/api/admin/auth");
      if (!response.ok) {
        throw new Error("Not authenticated");
      }
      return response.json();
    },
    retry: false,
    staleTime: 5 * 60 * 1000, // 5 minutes
  });

  useEffect(() => {
    if (isError) {
      router.push("/login?redirect=/admin");
    }
    if (authData || isError) {
      setIsLoading(false);
    }
  }, [authData, isError, router]);

  const handleLogout = async () => {
    try {
      const response = await fetch("/api/admin/auth", {
        method: "DELETE",
      });

      if (response.ok) {
        queryClient.clear();
        toast.success("Logged out successfully");
        router.push("/login");
      } else {
        throw new Error("Logout failed");
      }
    } catch {
      toast.error("Failed to logout");
    }
  };

  if (isLoading) {
    return (
      <div className="flex h-screen w-full items-center justify-center bg-background">
        <div className="flex flex-col items-center gap-4">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-4 w-32" />
        </div>
      </div>
    );
  }

  if (!authData?.authenticated) {
    return null;
  }

  return (
    <TooltipProvider delayDuration={0}>
      <div className="flex h-screen w-full overflow-hidden bg-background">
        {/* Desktop Sidebar */}
        <aside className="hidden lg:flex w-64 flex-col border-r bg-sidebar">
          <div className="flex h-14 items-center border-b border-sidebar-border px-4">
            <Link href="/admin" className="flex items-center gap-2">
              <span className="font-semibold text-sidebar-foreground">Admin Portal</span>
            </Link>
          </div>

          <ScrollArea className="flex-1">
            <SidebarNav pathname={pathname} />
          </ScrollArea>

          <div className="border-t border-sidebar-border p-3">
            <div className="flex items-center gap-3 rounded-md px-3 py-2 text-sm">
              <div className="flex-1 truncate">
                <p className="font-medium text-sidebar-foreground">{authData.user.username}</p>
                <p className="text-xs text-sidebar-foreground/70">Administrator</p>
              </div>
            </div>
            <Separator className="my-2 bg-sidebar-border" />
            <Button
              variant="ghost"
              className="w-full justify-start gap-3 text-sidebar-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground"
              onClick={handleLogout}
            >
              <LogOut className="h-4 w-4" />
