function formatActivityText(activity: ActivityItem) {
  const resourceMap: Record<string, string> = {
    article: "Article",
    project: "Project",
    certification: "Certification",
    book: "Book",
    media: "Media",
    message: "Message",
  };

  const actionMap: Record<string, string> = {
    create: "created",
    update: "updated",
    edit: "edited",
    delete: "deleted",
    login: "logged in",
    upload: "uploaded",
  };

  const resourceName = resourceMap[activity.resource] || activity.resource;
  const actionName = actionMap[activity.action] || activity.action;

  return `${actionName} ${resourceName.toLowerCase()}`;
}

