function ContentTable({ 
  type, 
  data,
  isLoading,
  onBulkDelete,
  onBulkPublish,
}: { 
  type: ContentType;
  data: any[];
  isLoading: boolean;
  onBulkDelete: (ids: string[]) => void;
  onBulkPublish: (ids: string[], publish: boolean) => void;
}) {
  const [sorting, setSorting] = useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
  const [columnVisibility, setColumnVisibility] = useState<VisibilityState>({});
  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});
  const [globalFilter, setGlobalFilter] = useState("");

  const columns = useMemo(() => getColumns(type), [type]);

  const table = useReactTable({
    data,
    columns,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onColumnVisibilityChange: setColumnVisibility,
    onRowSelectionChange: setRowSelection,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    state: {
      sorting,
      columnFilters,
      columnVisibility,
      rowSelection,
      globalFilter,
    },
    onGlobalFilterChange: setGlobalFilter,
  });

  const selectedRows = table.getFilteredSelectedRowModel().rows;
  const selectedIds = selectedRows.map((row) => row.original.id);

  const handleBulkDelete = () => {
    onBulkDelete(selectedIds);
    table.toggleAllPageRowsSelected(false);
  };

  const handleBulkPublish = (publish: boolean) => {
    onBulkPublish(selectedIds, publish);
    table.toggleAllPageRowsSelected(false);
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-2">
          <div className="h-9 w-72 bg-muted rounded-md animate-pulse" />
          <div className="h-9 w-24 bg-muted rounded-md animate-pulse" />
        </div>
        <div className="border rounded-md">
          <div className="h-96 bg-muted animate-pulse" />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Toolbar */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div className="flex items-center gap-2">
          <div className="relative">
            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search..."
              value={globalFilter}
              onChange={(e) => setGlobalFilter(e.target.value)}
              className="pl-8 w-[250px] sm:w-[300px]"
            />
          </div>
          {selectedRows.length > 0 && (
            <>
              <Button
                variant="outline"
                size="sm"
                onClick={() => table.toggleAllPageRowsSelected(false)}
              >
                Clear selection
              </Button>
              <span className="text-sm text-muted-foreground">
                {selectedRows.length} selected
              </span>
            </>
          )}
        </div>
        <div className="flex items-center gap-2">
          {selectedRows.length > 0 && type === "articles" && (
            <>
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleBulkPublish(true)}
              >
                <Eye className="mr-2 h-4 w-4" />
                Publish
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => handleBulkPublish(false)}
              >
                <EyeOff className="mr-2 h-4 w-4" />
                Unpublish
              </Button>
            </>
          )}
          {selectedRows.length > 0 && (
            <Button
              variant="destructive"
              size="sm"
              onClick={handleBulkDelete}
            >
              <Trash2 className="mr-2 h-4 w-4" />
              Delete ({selectedRows.length})
            </Button>
          )}
