// File type definitions
const FILE_TYPE_CONFIG = {
  image: {
    extensions: [".jpg", ".jpeg", ".png", ".gif", ".webp", ".svg", ".bmp", ".tiff"],
    mimeTypes: ["image/jpeg", "image/png", "image/gif", "image/webp", "image/svg+xml", "image/bmp", "image/tiff"],
    maxSize: 10 * 1024 * 1024, // 10MB
    icon: FileImage,
    label: "Image",
  },
  video: {
    extensions: [".mp4", ".webm", ".ogg", ".mov", ".avi", ".mkv"],
    mimeTypes: ["video/mp4", "video/webm", "video/ogg", "video/quicktime", "video/x-msvideo", "video/x-matroska"],
    maxSize: 100 * 1024 * 1024, // 100MB
    icon: FileVideo,
    label: "Video",
  },
  audio: {
    extensions: [".mp3", ".wav", ".ogg", ".m4a", ".flac", ".aac"],
    mimeTypes: ["audio/mpeg", "audio/wav", "audio/ogg", "audio/mp4", "audio/flac", "audio/aac"],
    maxSize: 50 * 1024 * 1024, // 50MB
    icon: FileAudio,
    label: "Audio",
  },
  pdf: {
    extensions: [".pdf"],
    mimeTypes: ["application/pdf"],
    maxSize: 20 * 1024 * 1024, // 20MB
    icon: FileText,
    label: "PDF",
  },
  document: {
    extensions: [".doc", ".docx", ".txt", ".rtf", ".odt"],
    mimeTypes: ["application/msword", "application/vnd.openxmlformats-officedocument.wordprocessingml.document", "text/plain", "application/rtf", "application/vnd.oasis.opendocument.text"],
    maxSize: 10 * 1024 * 1024, // 10MB
    icon: FileText,
    label: "Document",
  },
};

type FileType = keyof typeof FILE_TYPE_CONFIG;
type UploadStatus = "pending" | "uploading" | "success" | "error";

interface UploadFile {
  id: string;
  file: File;
  name: string;
  size: number;
  type: FileType;
  status: UploadStatus;
  progress: number;
  error?: string;
  url?: string;
  previewUrl?: string;
}

interface MediaUploaderProps {
  onUploadComplete?: (files: UploadFile[]) => void;
  onFileSelect?: (files: UploadFile[]) => void;
  acceptedTypes?: FileType[];
  maxFiles?: number;
  maxTotalSize?: number;
  className?: string;
  uploadEndpoint?: string;
}

function getFileType(file: File): FileType | null {
  for (const [type, config] of Object.entries(FILE_TYPE_CONFIG)) {
    if (config.mimeTypes.includes(file.type)) {
      return type as FileType;
    }
    // Check extension as fallback
    const ext = "." + file.name.split(".").pop()?.toLowerCase();
    if (config.extensions.includes(ext)) {
      return type as FileType;
    }
  }
  return null;
}

function formatFileSize(bytes: number): string {
  if (bytes === 0) return "0 B";
  const k = 1024;
  const sizes = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
}

function generateId(): string {
  return Math.random().toString(36).substring(2, 9);
}

