export function MediaUploader({
  onUploadComplete,
  onFileSelect,
  acceptedTypes,
  maxFiles = 10,
  maxTotalSize = 500 * 1024 * 1024, // 500MB
  className,
  uploadEndpoint = "/api/admin/upload",
}: MediaUploaderProps) {
  const [files, setFiles] = useState<UploadFile[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  const uploadMutation = useMutation({
    mutationFn: async (file: UploadFile) => {
      const formData = new FormData();
      formData.append("file", file.file);
      formData.append("type", file.type);

      const xhr = new XMLHttpRequest();

      return new Promise<{ url: string }>((resolve, reject) => {
        xhr.upload.addEventListener("progress", (event) => {
          if (event.lengthComputable) {
            const progress = Math.round((event.loaded * 100) / event.total);
            updateFileProgress(file.id, progress);
          }
        });

        xhr.addEventListener("load", () => {
          if (xhr.status === 200) {
            const response = JSON.parse(xhr.responseText);
            resolve(response);
          } else {
            reject(new Error("Upload failed"));
          }
        });

        xhr.addEventListener("error", () => {
          reject(new Error("Upload failed"));
        });

        xhr.open("POST", uploadEndpoint);
        xhr.send(formData);
      });
    },
    onSuccess: (data, file) => {
      updateFileStatus(file.id, "success", data.url);
      toast.success(`${file.name} uploaded successfully`);
    },
    onError: (_, file) => {
      updateFileStatus(file.id, "error", undefined, "Upload failed");
      toast.error(`Failed to upload ${file.name}`);
    },
  });

  const updateFileProgress = (id: string, progress: number) => {
    setFiles((prev) =>
      prev.map((f) => (f.id === id ? { ...f, progress } : f))
    );
  };

  const updateFileStatus = (
    id: string,
    status: UploadStatus,
    url?: string,
    error?: string
  ) => {
    setFiles((prev) =>
      prev.map((f) =>
        f.id === id ? { ...f, status, url, error, progress: status === "success" ? 100 : f.progress } : f
      )
    );
  };

  const removeFile = (id: string) => {
    setFiles((prev) => prev.filter((f) => f.id !== id));
  };

  const onDrop = useCallback(
    (acceptedFiles: File[]) => {
      setIsDragging(false);

      // Check max files limit
      if (files.length + acceptedFiles.length > maxFiles) {
        toast.error(`Maximum ${maxFiles} files allowed`);
        return;
      }

      // Calculate total size
      const currentSize = files.reduce((acc, f) => acc + f.size, 0);
      const newSize = acceptedFiles.reduce((acc, f) => acc + f.size, 0);
      if (currentSize + newSize > maxTotalSize) {
        toast.error(`Total size exceeds ${formatFileSize(maxTotalSize)}`);
        return;
      }

      // Process files
      const newFiles: UploadFile[] = acceptedFiles.map((file) => {
        const type = getFileType(file);
        const config = type ? FILE_TYPE_CONFIG[type] : null;

        // Check file size
        if (config && file.size > config.maxSize) {
          return {
            id: generateId(),
            file,
            name: file.name,
            size: file.size,
            type: type || "image",
            status: "error",
            progress: 0,
            error: `File size exceeds ${formatFileSize(config.maxSize)}`,
          };
        }

        // Create preview URL for images
        let previewUrl: string | undefined;
        if (type === "image" && file.type.startsWith("image/")) {
          previewUrl = URL.createObjectURL(file);
        }

        return {
          id: generateId(),
          file,
          name: file.name,
          size: file.size,
          type: type || "image",
          status: "pending",
          progress: 0,
          previewUrl,
        };
      });

      setFiles((prev) => [...prev, ...newFiles]);
      onFileSelect?.(newFiles);
    },
    [files, maxFiles, maxTotalSize, onFileSelect]
  );

  const { getRootProps, getInputProps, isDragActive, fileRejections } = useDropzone({
    onDrop,
    onDragEnter: () => setIsDragging(true),
    onDragLeave: () => setIsDragging(false),
    accept: acceptedTypes?.reduce((acc, type) => {
      const config = FILE_TYPE_CONFIG[type];
      if (config) {
        config.mimeTypes.forEach((mime) => {
          acc[mime] = config.extensions;
        });
      }
      return acc;
    }, {} as Record<string, string[]>),
    maxFiles,
  });

  const startUpload = async () => {
    const pendingFiles = files.filter((f) => f.status === "pending");

    for (const file of pendingFiles) {
      setFiles((prev) =>
        prev.map((f) => (f.id === file.id ? { ...f, status: "uploading" } : f))
      );
      uploadMutation.mutate(file);
    }
  };

  const cancelUpload = (id: string) => {
    // Note: XMLHttpRequest abort would need to be implemented for true cancellation
    updateFileStatus(id, "error", undefined, "Upload cancelled");
  };

  const clearAll = () => {
    setFiles([]);
  };

  const pendingCount = files.filter((f) => f.status === "pending").length;
  const uploadingCount = files.filter((f) => f.status === "uploading").length;
  const successCount = files.filter((f) => f.status === "success").length;
  const errorCount = files.filter((f) => f.status === "error").length;

  return (
    <div className={cn("space-y-4", className)}>
      {/* Dropzone */}
      <div
        {...getRootProps()}
        className={cn(
          "relative border-2 border-dashed rounded-lg p-8 text-center cursor-pointer transition-colors",
          isDragActive || isDragging
            ? "border-primary bg-primary/5"
            : "border-muted-foreground/25 hover:border-muted-foreground/50"
        )}
      >
        <input {...getInputProps()} />
        <div className="flex flex-col items-center gap-2">
          <div className="p-3 rounded-full bg-muted">
            <Upload className="h-6 w-6 text-muted-foreground" />
          </div>
          <div className="space-y-1">
            <p className="text-sm font-medium">
              {isDragActive ? "Drop files here" : "Drag & drop files here"}
            </p>
            <p className="text-xs text-muted-foreground">
              or click to browse (max {maxFiles} files, up to {formatFileSize(maxTotalSize)} total)
            </p>
          </div>
          {acceptedTypes && (
            <div className="flex flex-wrap justify-center gap-1 mt-2">
              {acceptedTypes.map((type) => (
                <Badge key={type} variant="secondary" className="text-xs">
                  {FILE_TYPE_CONFIG[type].label}
                </Badge>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* File rejections */}
      {fileRejections.length > 0 && (
        <div className="rounded-md bg-destructive/10 p-3 text-sm text-destructive">
          <div className="flex items-center gap-2">
            <AlertCircle className="h-4 w-4" />
            <span className="font-medium">Some files were rejected:</span>
          </div>
          <ul className="mt-1 ml-6 list-disc">
            {fileRejections.map(({ file, errors }) => (
              <li key={file.name}>
                {file.name}: {errors.map((e) => e.message).join(", ")}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* File list */}
      {files.length > 0 && (
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="text-sm font-medium">Files ({files.length})</span>
              {pendingCount > 0 && (
                <Badge variant="secondary">{pendingCount} pending</Badge>
              )}
              {uploadingCount > 0 && (
                <Badge variant="default" className="animate-pulse">
                  {uploadingCount} uploading
                </Badge>
              )}
              {successCount > 0 && (
                <Badge variant="outline" className="text-emerald-500 border-emerald-500">
                  <Check className="h-3 w-3 mr-1" />
                  {successCount} done
                </Badge>
              )}
              {errorCount > 0 && (
                <Badge variant="outline" className="text-destructive border-destructive">
                  <AlertCircle className="h-3 w-3 mr-1" />
                  {errorCount} failed
                </Badge>
              )}
            </div>
            <div className="flex items-center gap-2">
              {pendingCount > 0 && (
                <Button size="sm" onClick={startUpload}>
                  Upload {pendingCount} file{pendingCount > 1 ? "s" : ""}
                </Button>
              )}
              <Button size="sm" variant="ghost" onClick={clearAll}>
                <Trash2 className="h-4 w-4 mr-1" />
                Clear all
              </Button>
            </div>
          </div>

          <ScrollArea className="h-[300px] rounded-md border">
            <div className="p-3 space-y-3">
              {files.map((file) => (
                <div
                  key={file.id}
                  className={cn(
                    "flex items-center gap-3 p-3 rounded-md border transition-colors",
                    file.status === "error" && "border-destructive bg-destructive/5",
                    file.status === "success" && "border-emerald-500 bg-emerald-50/50 dark:bg-emerald-950/20"
                  )}
                >
                  {/* Preview */}
                  {file.type === "image" && (
                    <ImagePreview file={file} previewUrl={file.previewUrl} />
                  )}
                  {file.type === "video" && <VideoPreview file={file} />}
                  {file.type === "pdf" && <PDFPreview file={file} />}
                  {file.type === "audio" && (
                    <div className="flex items-center justify-center w-16 h-16 rounded-md border bg-muted">
                      <FileAudio className="h-6 w-6 text-muted-foreground" />
                    </div>
                  )}
                  {file.type === "document" && (
                    <div className="flex items-center justify-center w-16 h-16 rounded-md border bg-muted">
                      <FileText className="h-6 w-6 text-muted-foreground" />
                    </div>
                  )}

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <p className="font-medium text-sm truncate">{file.name}</p>
                      <Badge variant="secondary" className="text-xs shrink-0">
                        {FILE_TYPE_CONFIG[file.type].label}
                      </Badge>
                    </div>
                    <p className="text-xs text-muted-foreground">
                      {formatFileSize(file.size)}
                    </p>

                    {/* Progress bar */}
                    {(file.status === "uploading" || file.status === "pending") && (
                      <div className="mt-2">
                        <Progress value={file.progress} className="h-1.5" />
                        <p className="text-xs text-muted-foreground mt-1">
                          {file.status === "uploading" ? `${file.progress}%` : "Ready to upload"}
                        </p>
                      </div>
                    )}

                    {/* Error message */}
                    {file.error && (
                      <p className="text-xs text-destructive mt-1">{file.error}</p>
                    )}

                    {/* Success indicator */}
                    {file.status === "success" && (
                      <div className="flex items-center gap-1 mt-1 text-xs text-emerald-500">
                        <Check className="h-3 w-3" />
                        Upload complete
                      </div>
                    )}
                  </div>

                  {/* Actions */}
                  <div className="flex items-center gap-1">
                    {file.status === "uploading" && (
                      <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => cancelUpload(file.id)}
                      >
                        Cancel
                      </Button>
                    )}
                    <Button
                      size="icon"
                      variant="ghost"
                      className="h-8 w-8"
                      onClick={() => removeFile(file.id)}
                      disabled={file.status === "uploading"}
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          </ScrollArea>
        </div>
      )}
    </div>
  );
}

// Simple export for just the dropzone component
export function MediaDropzone({
  onDrop,
  acceptedTypes,
  maxFiles,
  className,
}: {
  onDrop: (files: File[]) => void;
  acceptedTypes?: FileType[];
  maxFiles?: number;
  className?: string;
}) {
  const [isDragging, setIsDragging] = useState(false);

  const { getRootProps, getInputProps, isDragActive, fileRejections } = useDropzone({
    onDrop: (files) => {
      setIsDragging(false);
      onDrop(files);
    },
    onDragEnter: () => setIsDragging(true),
    onDragLeave: () => setIsDragging(false),
    accept: acceptedTypes?.reduce((acc, type) => {
      const config = FILE_TYPE_CONFIG[type];
      if (config) {
        config.mimeTypes.forEach((mime) => {
          acc[mime] = config.extensions;
        });
      }
      return acc;
    }, {} as Record<string, string[]>),
    maxFiles,
  });

  return (
    <div
      {...getRootProps()}
      className={cn(
        "relative border-2 border-dashed rounded-lg p-8 text-center cursor-pointer transition-colors",
        isDragActive || isDragging
          ? "border-primary bg-primary/5"
          : "border-muted-foreground/25 hover:border-muted-foreground/50",
        className
      )}
    >
      <input {...getInputProps()} />
      <div className="flex flex-col items-center gap-2">
        <div className="p-3 rounded-full bg-muted">
          <Upload className="h-6 w-6 text-muted-foreground" />
        </div>
        <div className="space-y-1">
          <p className="text-sm font-medium">
            {isDragActive ? "Drop files here" : "Drag & drop files here"}
          </p>
          <p className="text-xs text-muted-foreground">
            or click to browse
          </p>
        </div>
      </div>
    </div>
  );
}
